function ScreenshotTool() {
  const [url, setUrl] = React.useState('https://example.com');
  const [capturing, setCapturing] = React.useState(false);
  const [screenshot, setScreenshot] = React.useState(null);
  const [history, setHistory] = React.useState([
    { url: 'https://github.com', time: '2m ago' },
    { url: 'https://news.ycombinator.com', time: '15m ago' }
  ]);

  function capture() {
    if (!url.trim()) return;
    setCapturing(true);
    setScreenshot(null);
    setTimeout(() => {
      setScreenshot({ url, id: Math.random().toString(36).slice(2, 8) });
      setHistory([{ url, time: 'just now' }, ...history]);
      setCapturing(false);
    }, 1200);
  }

  return (
    <div style={{ fontFamily: 'system-ui, sans-serif', padding: 16, background: '#fff', borderRadius: 12, height: '100%', boxSizing: 'border-box', display: 'flex', flexDirection: 'column' }}>
      <h2 style={{ margin: '0 0 12px 0', fontSize: 18, color: '#1a1a1a' }}>Screenshot Tool</h2>
      <div style={{ display: 'flex', gap: 8, marginBottom: 12 }}>
        <input
          value={url}
          onChange={e => setUrl(e.target.value)}
          placeholder="https://example.com"
          style={{ flex: 1, padding: '8px 12px', borderRadius: 6, border: '1px solid #ddd', fontSize: 13 }}
        />
        <button
          onClick={capture}
          disabled={capturing}
          style={{ padding: '8px 18px', borderRadius: 6, border: 'none', background: capturing ? '#9ca3af' : '#0d9488', color: '#fff', fontSize: 13, cursor: capturing ? 'not-allowed' : 'pointer' }}
        >
          {capturing ? 'Capturing...' : 'Capture'}
        </button>
      </div>
      <div style={{ flex: 1, borderRadius: 8, background: '#f3f4f6', border: '1px solid #e5e7eb', display: 'flex', flexDirection: 'column', overflow: 'hidden', marginBottom: 12 }}>
        <div style={{ padding: '6px 10px', background: '#e5e7eb', fontSize: 11, color: '#6b7280', display: 'flex', alignItems: 'center', gap: 6 }}>
          <div style={{ width: 8, height: 8, borderRadius: '50%', background: '#ef4444' }} />
          <div style={{ width: 8, height: 8, borderRadius: '50%', background: '#f59e0b' }} />
          <div style={{ width: 8, height: 8, borderRadius: '50%', background: '#22c55e' }} />
          <span style={{ marginLeft: 6, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{screenshot ? screenshot.url : url}</span>
        </div>
        <div style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', position: 'relative' }}>
          {capturing ? (
            <div style={{ textAlign: 'center', color: '#6b7280' }}>
              <div style={{ width: 28, height: 28, border: '3px solid #e5e7eb', borderTopColor: '#0d9488', borderRadius: '50%', margin: '0 auto 8px' }} />
              <div style={{ fontSize: 13 }}>Capturing screenshot...</div>
            </div>
          ) : screenshot ? (
            <div style={{ textAlign: 'center', padding: 20 }}>
              <div style={{ width: 160, height: 100, borderRadius: 6, background: 'linear-gradient(135deg, #99f6e4 0%, #5eead4 100%)', margin: '0 auto 10px', display: 'flex', alignItems: 'center', justifyContent: 'center', boxShadow: '0 4px 6px rgba(0,0,0,0.1)' }}>
                <span style={{ fontSize: 40 }}>\ud83d\udcf7</span>
              </div>
              <div style={{ fontSize: 11, color: '#6b7280' }}>Screenshot ID: {screenshot.id}</div>
            </div>
          ) : (
            <div style={{ color: '#9ca3af', fontSize: 13, textAlign: 'center' }}>Enter a URL and click Capture</div>
          )}
        </div>
      </div>
      <div style={{ maxHeight: 90, overflowY: 'auto' }}>
        <div style={{ fontSize: 11, color: '#9ca3af', marginBottom: 4 }}>History</div>
        {history.map((h, i) => (
          <div
            key={i}
            onClick={() => setUrl(h.url)}
            style={{ display: 'flex', justifyContent: 'space-between', padding: '6px 10px', borderRadius: 6, background: '#f9fafb', marginBottom: 4, fontSize: 12, color: '#4b5563', cursor: 'pointer' }}
          >
            <span style={{ overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{h.url}</span>
            <span style={{ color: '#9ca3af', fontSize: 11, flexShrink: 0 }}>{h.time}</span>
          </div>
        ))}
      </div>
    </div>
  );
}
render(<ScreenshotTool/>);
